const t = await sequelize.transaction();
try {
  const passwordHash = await bcrypt.hash(body.password, 10);
  const user = await User.create(
    { email: body.email, username: body.username, passwordHash },
    { transaction: t }
  );
  await t.commit();
  const token = fastify.jwt.sign({ id: user.id }, { expiresIn: '7d' });
  return reply.code(201).send({ token, user: toUserDto(user) });
} catch (err) {
  await t.rollback();
  if (err instanceof UniqueConstraintError) {
    const field = err.errors[0]?.path; // 'email' ou 'username'
    return reply.code(409).send({ errors: { [field]: ['already taken'] } });
  }
  throw err;
}

