  const comment = await Comment.findOne({
    where: { id: req.params.commentId, articleId: article.id }
  });
  if (!comment) return reply.code(404).send({ error: 'Comment not found' });

  // Double autorisation: auteur commentaire OU auteur article
  const canDelete = comment.authorId === req.user.id || article.authorId === req.user.id;
  if (!canDelete) return reply.code(403).send({ errors: { body: ['Forbidden'] } });

  await comment.destroy();
  return reply.code(200).send({ message: 'Comment deleted' });
});

